mapper.select:
/* 장치구분별 알람건수 조회 */ select count( case when device_type = '1' then 1 end ) as cnt_pcs, count( case when device_type = '2' then 1 end ) as cnt_bms, count( case when device_type = '3' then 1 end ) as cnt_pv, count( case when device_type = '4' then 1 end ) as cnt_ioe,
count( case when device_type not in ('1', '2', '3', '4') then 1 end ) as cnt_etc from ( select alarm_idx, site_id, device_id, device_type, std_date, alarm_type, alarm_msg, alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_note, reg_date, mod_date from tb_alarm where 1=1
and site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
) a

/* 알람 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.alarm_idx, a.site_id, a.device_id, b.device_name, a.device_type, 
				case a.device_type when 1 then 'PCS'
					when 2 then 'BMS'
					when 3 then 'PV'
					when 4 then '부하측정기기'
					when 5 then 'PV모니터링기기'
					else 'ESS모니터링기기' end as device_type_nm,
				a.std_date, a.alarm_type, a.alarm_msg, 
				a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_note, a.reg_date, a.mod_date
			from tb_alarm a, tb_device b
			where a.device_id = b.device_id
			
			and a.site_id = #{siteId }
			
			and a.alarm_type = #{alarmType }
			
			and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by a.std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
limit #{startNum }, #{pageRowCnt }

/* 알람 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.alarm_idx, a.site_id, a.device_id, b.device_name, a.device_type, 
				case a.device_type when 1 then 'PCS'
					when 2 then 'BMS'
					when 3 then 'PV'
					when 4 then '부하측정기기'
					when 5 then 'PV모니터링기기'
					else 'ESS모니터링기기' end as device_type_nm,
				a.std_date, a.alarm_type, a.alarm_msg, 
				a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_note, a.reg_date, a.mod_date
			from tb_alarm a, tb_device b
			where a.device_id = b.device_id
			
			and a.site_id = #{siteId }
			
			and a.alarm_type = #{alarmType }
			
			and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by a.std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 알람 수신자 목록 조회 */
select 
	sms_user_idx, site_id, `name` as addressee_name, mobile, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_sms_user
where del_yn = 'N'

and site_id = #{siteId }
